// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Access-recertification report for a View
	// (GET /access/recertification/{view})
	GetAccessRecertification(w http.ResponseWriter, r *http.Request, view string)
	// Attest a View's access grants (recertification)
	// (POST /access/recertification/{view})
	AttestAccessRecertification(w http.ResponseWriter, r *http.Request, view string)
	// List declared plugin Actuators
	// (GET /actuators)
	ListActuators(w http.ResponseWriter, r *http.Request)
	// Get one Actuator with its live registry status
	// (GET /actuators/{name})
	GetActuator(w http.ResponseWriter, r *http.Request, name string)
	// Adopt an observed object into a reviewable Named-Kind bundle (ADR-0086/0088)
	// (POST /adoptions)
	AdoptObject(w http.ResponseWriter, r *http.Request)
	// Fetch an adoption Run's status and (on success) its emitted bundle (ADR-0088)
	// (GET /adoptions/{runId})
	GetAdoption(w http.ResponseWriter, r *http.Request, runId string)
	// List declared Assignments (CaC-only, ADR-0023)
	// (GET /assignments)
	ListAssignments(w http.ResponseWriter, r *http.Request)
	// The audit stream
	// (GET /audit)
	ListAudit(w http.ResponseWriter, r *http.Request, params ListAuditParams)
	// The next audit batch to ship to a SIEM sink
	// (GET /audit/forward/{sink})
	GetForwardBatch(w http.ResponseWriter, r *http.Request, sink string, params GetForwardBatchParams)
	// A SIEM sink's non-secret forwarding config
	// (GET /audit/forward/{sink}/config)
	GetForwardConfig(w http.ResponseWriter, r *http.Request, sink string)
	// A SIEM sink's recent delivery outcomes
	// (GET /audit/forward/{sink}/deliveries)
	ListForwardDeliveries(w http.ResponseWriter, r *http.Request, sink string)
	// Report a SIEM delivery outcome
	// (POST /audit/forward/{sink}/report)
	ReportForward(w http.ResponseWriter, r *http.Request, sink string)
	// Verify the audit stream's tamper-evidence chain
	// (GET /audit/verify)
	VerifyAudit(w http.ResponseWriter, r *http.Request)
	// List declared Baselines
	// (GET /baselines)
	ListBaselines(w http.ResponseWriter, r *http.Request)
	// Get a declared Baseline
	// (GET /baselines/{name})
	GetBaseline(w http.ResponseWriter, r *http.Request, name string)
	// List declared Blueprint versions (CaC-only, ADR-0023)
	// (GET /blueprints)
	ListBlueprints(w http.ResponseWriter, r *http.Request)
	// List capability→provider bindings
	// (GET /capability-bindings)
	ListCapabilityBindings(w http.ResponseWriter, r *http.Request)
	// Get one capability-binding
	// (GET /capability-bindings/{name})
	GetCapabilityBinding(w http.ResponseWriter, r *http.Request, name string)
	// Latest Intent-compile status — membership deltas, pauses, errors
	// (GET /compile)
	GetCompileStatus(w http.ResponseWriter, r *http.Request)
	// Compliance rollup for a framework
	// (GET /compliance/{framework})
	GetComplianceReport(w http.ResponseWriter, r *http.Request, framework string, params GetComplianceReportParams)
	// List declared Connectors
	// (GET /connectors)
	ListConnectors(w http.ResponseWriter, r *http.Request)
	// Get one Connector with its live registry status
	// (GET /connectors/{name})
	GetConnector(w http.ResponseWriter, r *http.Request, name string)
	// List pinned Contracts
	// (GET /contracts)
	ListContracts(w http.ResponseWriter, r *http.Request)
	// List CredentialRef pointers the Principal may read
	// (GET /credential-refs)
	ListCredentialRefs(w http.ResponseWriter, r *http.Request)
	// Get one CredentialRef pointer (reader grant required)
	// (GET /credential-refs/{name})
	GetCredentialRef(w http.ResponseWriter, r *http.Request, name string)
	// Declare a CredentialRef pointer (admin grant required)
	// (PUT /credential-refs/{name})
	DeclareCredentialRef(w http.ResponseWriter, r *http.Request, name string)
	// Reconcile the graph's Views to a declared desired state
	// (POST /desired-state/apply)
	DesiredStateApply(w http.ResponseWriter, r *http.Request)
	// Diff a declared desired state against the graph's Views
	// (POST /desired-state/plan)
	DesiredStatePlan(w http.ResponseWriter, r *http.Request)
	// List declared Emitters
	// (GET /emitters)
	ListEmitters(w http.ResponseWriter, r *http.Request)
	// Get one Entity with its Facets and per-attribute Provenance
	// (GET /entities/{id})
	GetEntity(w http.ResponseWriter, r *http.Request, id string)
	// Download a sealed Evidence bundle (integrity-verified)
	// (GET /evidence/{id}/download)
	DownloadEvidence(w http.ResponseWriter, r *http.Request, id string)
	// List Findings
	// (GET /findings)
	ListFindings(w http.ResponseWriter, r *http.Request, params ListFindingsParams)
	// Get a Finding
	// (GET /findings/{id})
	GetFinding(w http.ResponseWriter, r *http.Request, id string)
	// Get a Finding's Evidence manifest
	// (GET /findings/{id}/evidence)
	GetFindingEvidence(w http.ResponseWriter, r *http.Request, id string)
	// List Gates (the approval inbox)
	// (GET /gates)
	ListGates(w http.ResponseWriter, r *http.Request, params ListGatesParams)
	// Approve or deny a pending Gate
	// (POST /gates/{id}/decision)
	DecideGate(w http.ResponseWriter, r *http.Request, id string)
	// List declared Intents (CaC-only, ADR-0023)
	// (GET /intents)
	ListIntents(w http.ResponseWriter, r *http.Request)
	// List recent Run summaries
	// (GET /runs)
	ListRuns(w http.ResponseWriter, r *http.Request, params ListRunsParams)
	// Start a Run of the Phase-0 Workflow against a View
	// (POST /runs)
	StartRun(w http.ResponseWriter, r *http.Request)
	// Get a Run summary
	// (GET /runs/{id})
	GetRun(w http.ResponseWriter, r *http.Request, id RunID)
	// Request cancellation of a running Run
	// (POST /runs/{id}/cancel)
	CancelRun(w http.ResponseWriter, r *http.Request, id RunID)
	// Live SSE tail of the Run's full task-event stream
	// (GET /runs/{id}/events)
	TailRunEvents(w http.ResponseWriter, r *http.Request, id RunID)
	// List declared Sites
	// (GET /sites)
	ListSites(w http.ResponseWriter, r *http.Request)
	// Get one declared Site
	// (GET /sites/{name})
	GetSite(w http.ResponseWriter, r *http.Request, name string)
	// List registered Sources with home Cell + runtime home-ownership state
	// (GET /sources)
	ListSources(w http.ResponseWriter, r *http.Request)
	// Destination-Cell adopt of a re-homed Source (peer-internal, ADR-0044 slice 7)
	// (POST /sources/rehome-adopt)
	AdoptRehomedSource(w http.ResponseWriter, r *http.Request)
	// Get one Source — returns it only if THIS Cell homes it
	// (GET /sources/{name})
	GetSource(w http.ResponseWriter, r *http.Request, name SourceName)
	// Fenced cross-Cell re-home of a Source to another Cell (ADR-0044 slice 7)
	// (POST /sources/{name}/rehome)
	RehomeSource(w http.ResponseWriter, r *http.Request, name SourceName)
	// List declared Triggers
	// (GET /triggers)
	ListTriggers(w http.ResponseWriter, r *http.Request)
	// Get one Trigger with its live schedule state
	// (GET /triggers/{name})
	GetTrigger(w http.ResponseWriter, r *http.Request, name string)
	// Per-Principal MCP usage accounting
	// (GET /usage)
	ListUsage(w http.ResponseWriter, r *http.Request, params ListUsageParams)
	// List Views
	// (GET /views)
	ListViews(w http.ResponseWriter, r *http.Request)
	// Get a View (versioned, CaC-declared graph query)
	// (GET /views/{name})
	GetView(w http.ResponseWriter, r *http.Request, name ViewName)
	// Declare a View's selector (bumps the version on change)
	// (PUT /views/{name})
	DeclareView(w http.ResponseWriter, r *http.Request, name ViewName)
	// Resolve the View's live Entity set
	// (GET /views/{name}/entities)
	ResolveView(w http.ResponseWriter, r *http.Request, name ViewName, params ResolveViewParams)
	// List recent WorkflowRuns
	// (GET /workflow-runs)
	ListWorkflowRuns(w http.ResponseWriter, r *http.Request, params ListWorkflowRunsParams)
	// Get one WorkflowRun with per-Step outcomes
	// (GET /workflow-runs/{id})
	GetWorkflowRun(w http.ResponseWriter, r *http.Request, id string)
	// List declared Workflows
	// (GET /workflows)
	ListWorkflows(w http.ResponseWriter, r *http.Request)
	// Get one Workflow declaration
	// (GET /workflows/{name})
	GetWorkflow(w http.ResponseWriter, r *http.Request, name string)
	// Start one execution of a Workflow
	// (POST /workflows/{name}/runs)
	StartWorkflowRun(w http.ResponseWriter, r *http.Request, name string)
}

